#!/bin/bash
source ~/.zshrc
set -e
PROJECT="gatekipa-bbd1c"

echo -n "sk_test_3e9411f24beddce6556d6a55e07d4eb518cfc526" > /tmp/paystack.txt
npx -y firebase-tools functions:secrets:set PAYSTACK_SECRET_KEY --data-file /tmp/paystack.txt --project $PROJECT

echo -n "at_test_" > /tmp/bridge_access.txt
npx -y firebase-tools functions:secrets:set BRIDGECARD_ACCESS_TOKEN --data-file /tmp/bridge_access.txt --project $PROJECT

echo -n "sk_test_" > /tmp/bridge_secret.txt
npx -y firebase-tools functions:secrets:set BRIDGECARD_SECRET_KEY --data-file /tmp/bridge_secret.txt --project $PROJECT

echo -n "whsec_test_" > /tmp/bridge_whsec.txt
npx -y firebase-tools functions:secrets:set BRIDGECARD_WEBHOOK_SECRET --data-file /tmp/bridge_whsec.txt --project $PROJECT

rm /tmp/paystack.txt /tmp/bridge_access.txt /tmp/bridge_secret.txt /tmp/bridge_whsec.txt
echo "Secrets successfully propagated."
